package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.text.InputType
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey

private const val PREFS_NAME = "auth_prefs"
private const val KEY_AUTHENTICATED = "authenticated"
private const val KEY_PASSWORD = "password"

object AuthPrefs {
    fun prefs(context: Context): SharedPreferences {
        return try {
            val masterKey = MasterKey.Builder(context)
                .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                .build()
            EncryptedSharedPreferences.create(
                context,
                PREFS_NAME,
                masterKey,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            )
        } catch (_: Throwable) {
            context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        }
    }

    fun isAuthenticated(context: Context): Boolean =
        prefs(context).getBoolean(KEY_AUTHENTICATED, false)

    fun setAuthenticated(context: Context, value: Boolean) {
        prefs(context).edit().putBoolean(KEY_AUTHENTICATED, value).apply()
    }

    fun getPassword(context: Context): String? =
        prefs(context).getString(KEY_PASSWORD, null)

    fun setPassword(context: Context, password: String) {
        prefs(context).edit().putString(KEY_PASSWORD, password).apply()
    }

    fun clear(context: Context) {
        prefs(context).edit().clear().apply()
    }
}

class AuthGateActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (AuthPrefs.isAuthenticated(this)) {
            goHome()
            return
        }

        startActivity(Intent(this, LoginActivity::class.java))
        finish()
    }

    private fun goHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }
}

class LoginActivity : AppCompatActivity() {

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    private val enrollLauncher = registerForActivityResult(ActivityResultContracts.StartActivityForResult()) {
        // User returns from enrollment. Try biometric again.
        showBiometricIfAvailableOrPassword()
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        if (AuthPrefs.isAuthenticated(this)) {
            goHome()
            return
        }

        setupBiometric()

        findViewById<Button>(R.id.btn_biometric)?.setOnClickListener {
            showBiometricIfAvailableOrPassword(forceBiometric = true)
        }

        findViewById<Button>(R.id.btn_password_login)?.setOnClickListener {
            showPasswordDialog()
        }

        showBiometricIfAvailableOrPassword()
    }

    private fun setupBiometric() {
        val executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor, object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                onAuthSuccess()
            }

            override fun onAuthenticationFailed() {
                super.onAuthenticationFailed()
                Toast.makeText(this@LoginActivity, "Fingerprint not recognized. Try again or use password.", Toast.LENGTH_SHORT).show()
            }

            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                super.onAuthenticationError(errorCode, errString)
                when (errorCode) {
                    BiometricPrompt.ERROR_NEGATIVE_BUTTON,
                    BiometricPrompt.ERROR_USER_CANCELED,
                    BiometricPrompt.ERROR_CANCELED -> {
                        // User chose password or canceled; keep them on login.
                    }
                    BiometricPrompt.ERROR_NO_BIOMETRICS,
                    BiometricPrompt.ERROR_HW_NOT_PRESENT,
                    BiometricPrompt.ERROR_HW_UNAVAILABLE -> {
                        Toast.makeText(this@LoginActivity, "Biometric unavailable. Use password.", Toast.LENGTH_SHORT).show()
                        showPasswordDialog()
                    }
                    BiometricPrompt.ERROR_LOCKOUT,
                    BiometricPrompt.ERROR_LOCKOUT_PERMANENT -> {
                        Toast.makeText(this@LoginActivity, "Too many attempts. Use password.", Toast.LENGTH_SHORT).show()
                        showPasswordDialog()
                    }
                    else -> {
                        Toast.makeText(this@LoginActivity, errString, Toast.LENGTH_SHORT).show()
                    }
                }
            }
        })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Unlock with fingerprint")
            .setSubtitle("Quickly sign in using your fingerprint")
            .setDescription("You can always use your password instead.")
            .setNegativeButtonText("Use password")
            .build()
    }

    private fun showBiometricIfAvailableOrPassword(forceBiometric: Boolean = false) {
        val biometricManager = BiometricManager.from(this)
        val canAuth = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG)

        val hasPassword = !AuthPrefs.getPassword(this).isNullOrEmpty()

        when (canAuth) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                biometricPrompt.authenticate(promptInfo)
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                if (forceBiometric) {
                    showEnrollDialog()
                } else {
                    if (hasPassword) {
                        showPasswordDialog()
                    } else {
                        showSetPasswordDialog()
                    }
                }
            }
            else -> {
                if (hasPassword) {
                    showPasswordDialog()
                } else {
                    showSetPasswordDialog()
                }
            }
        }
    }

    private fun showEnrollDialog() {
        AlertDialog.Builder(this)
            .setTitle("Set up fingerprint")
            .setMessage("No fingerprint is enrolled on this device. Would you like to add one now?")
            .setPositiveButton("Open settings") { _, _ ->
                val enrollIntent = Intent(android.provider.Settings.ACTION_BIOMETRIC_ENROLL).apply {
                    putExtra(
                        android.provider.Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED,
                        BiometricManager.Authenticators.BIOMETRIC_STRONG
                    )
                }
                enrollLauncher.launch(enrollIntent)
            }
            .setNegativeButton("Use password") { _, _ ->
                showPasswordDialog()
            }
            .show()
    }

    private fun showPasswordDialog() {
        val saved = AuthPrefs.getPassword(this)

        if (saved.isNullOrEmpty()) {
            showSetPasswordDialog()
            return
        }

        val input = EditText(this).apply {
            inputType = InputType.TYPE_CLASS_TEXT or InputType.TYPE_TEXT_VARIATION_PASSWORD
            hint = "Password"
        }

        AlertDialog.Builder(this)
            .setTitle("Sign in with password")
            .setView(input)
            .setPositiveButton("Sign in") { _, _ ->
                val entered = input.text?.toString().orEmpty()
                if (entered == saved) {
                    onAuthSuccess()
                } else {
                    Toast.makeText(this, "Incorrect password. Try again.", Toast.LENGTH_SHORT).show()
                }
            }
            .setNegativeButton("Cancel", null)
            .show()
    }

    private fun showSetPasswordDialog() {
        val input = EditText(this).apply {
            inputType = InputType.TYPE_CLASS_TEXT or InputType.TYPE_TEXT_VARIATION_PASSWORD
            hint = "Create a password"
        }

        AlertDialog.Builder(this)
            .setTitle("Create a password")
            .setMessage("Set a password to use when fingerprint isn't available.")
            .setView(input)
            .setPositiveButton("Save") { _, _ ->
                val pass = input.text?.toString().orEmpty()
                if (pass.length < 4) {
                    Toast.makeText(this, "Password must be at least 4 characters.", Toast.LENGTH_SHORT).show()
                    return@setPositiveButton
                }
                AuthPrefs.setPassword(this, pass)
                Toast.makeText(this, "Password saved. You can now sign in.", Toast.LENGTH_SHORT).show()
                showPasswordDialog()
            }
            .setNegativeButton("Cancel", null)
            .show()
    }

    private fun onAuthSuccess() {
        AuthPrefs.setAuthenticated(this, true)
        goHome()
    }

    private fun goHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }
}

class HomeActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_home)

        findViewById<Button>(R.id.btn_logout)?.setOnClickListener {
            AuthPrefs.setAuthenticated(this, false)
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }
}